var query = ($json.query || '').trim();
var queryLower = query.toLowerCase();
var telefone = ($json.telefone || '').replace('@s.whatsapp.net', '');

var action = 'consultar';

if (queryLower.indexOf('definir') > -1 || queryLower.indexOf('establecer') > -1 || queryLower.indexOf('limite') > -1 || queryLower.indexOf('teto') > -1 || queryLower.indexOf('definir') > -1 || queryLower.indexOf('set') > -1) {
  action = 'definir';
} else if (queryLower.indexOf('eliminar') > -1 || queryLower.indexOf('borrar') > -1 || queryLower.indexOf('quitar') > -1 || queryLower.indexOf('excluir') > -1 || queryLower.indexOf('apagar') > -1 || queryLower.indexOf('remover') > -1) {
  action = 'eliminar';
}

var stopWords = ['definir','establecer','limite','teto','set','eliminar','borrar','quitar','excluir','apagar','remover','presupuesto','presupuestos','orcamento','la','el','una','un','de','por','para','favor','puede','puedes','consultar','ver','mostrar','mis','meus','minhas','quero','quiero','cuanto','quanto','como','esta','gastar','gasto','categoria'];

var words = queryLower.replace(/[?!.,;:$]/g, '').split(/\s+/);
var significant = [];
var monto = 0;

for (var i = 0; i < words.length; i++) {
  var num = parseFloat(words[i]);
  if (!isNaN(num) && num > 0) {
    monto = num;
  } else if (words[i].length > 1 && stopWords.indexOf(words[i]) === -1) {
    significant.push(words[i]);
  }
}

var categoria = '';
for (var j = 0; j < significant.length; j++) {
  var w = significant[j];
  categoria += w.charAt(0).toUpperCase() + w.slice(1);
  if (j < significant.length - 1) categoria += ' ';
}

return [{ json: { action: action, categoria: categoria, monto_limite: monto, telefone: telefone } }];

var parsed = $node['Parsear Query'].json;
var resposta = $input.first().json;
var action = parsed.action;
var presupuestos = resposta.presupuestos || [];

if (action === 'consultar') {
  if (presupuestos.length === 0) {
    return [{ json: { skip: true, mensagem: '📊 No tienes presupuestos definidos para este mes.' } }];
  }
  var lista = '';
  for (var i = 0; i < presupuestos.length; i++) {
    var p = presupuestos[i];
    lista += p.alerta + ' *' + p.categoria + '*\n';
    lista += '  Límite: ' + p.limite + ' | Gastado: ' + p.gastado + ' (' + p.porcentaje + ')\n';
    lista += '  Restante: ' + p.restante + '\n\n';
  }
  return [{ json: { skip: true, mensagem: '📊 *Tus Presupuestos:*\n\n' + lista.trim() } }];
}

if (action === 'definir') {
  if (!parsed.categoria) {
    return [{ json: { skip: true, mensagem: '⚠️ Necesito la categoría. Ejemplo: definir presupuesto Alimentación 500000' } }];
  }
  if (!parsed.monto_limite || parsed.monto_limite <= 0) {
    return [{ json: { skip: true, mensagem: '⚠️ Necesito el monto. Ejemplo: definir presupuesto Alimentación 500000' } }];
  }
  return [{ json: { skip: false, action: 'definir', categoria: parsed.categoria, monto_limite: parsed.monto_limite, telefone: parsed.telefone } }];
}

if (action === 'eliminar') {
  if (!parsed.categoria) {
    if (presupuestos.length === 0) {
      return [{ json: { skip: true, mensagem: '📊 No tienes presupuestos para eliminar.' } }];
    }
    var lista2 = '';
    for (var k = 0; k < presupuestos.length; k++) {
      lista2 += '• ' + presupuestos[k].categoria + '\n';
    }
    return [{ json: { skip: true, mensagem: '⚠️ Necesito saber cuál. Presupuestos activos:\n\n' + lista2.trim() } }];
  }
  return [{ json: { skip: false, action: 'eliminar', categoria: parsed.categoria, telefone: parsed.telefone } }];
}

return [{ json: { skip: true, mensagem: '⚠️ Usa: ver presupuestos, definir presupuesto Alimentación 500000, eliminar presupuesto Alimentación' } }];

var resposta = $input.first().json;

if (resposta.mensagem) {
  return [{ json: { success: true, message: resposta.mensagem } }];
}

if (resposta.success) {
  return [{ json: { success: true, message: resposta.message || '✅ Operación completada.' } }];
}

return [{ json: { success: false, message: '❌ Error: ' + (resposta.error || 'Algo salió mal.') } }];
